```julia
using Random, Accessors

struct A{T,R}
    state::Float64
    rng::R
    value::T
    A(state, rng::R, value::T) where {T,R} = new{T,R}(state, rng, value)
    A{T,R}(state, rng) where {T,R} = new{T,R}(state, rng) # only difference
end

struct B{T,R}
    state::Float64
    rng::R
    value::T
    B(state, rng::R, value::T) where {T,R} = new{T,R}(state, rng, value)
end

function update_A!(s)
    for x in 1:10^7
        s = A(s.state + x, s.rng, s.value)
    end
    return s
end
function update_B!(s)
    for x in 1:10^7
        s = B(s.state + x, s.rng, s.value)
    end
    return s
end

rng = Xoshiro(42);
a = A(0.0, rng, 0)
b = B(0.0, rng, 0)

update_A!(a);
update_B!(b);
@time update_A!(a);
@time update_B!(b);
```

which gives

```julia
julia> @time update_A!(a);
  0.050859 seconds (10.00 M allocations: 305.176 MiB, 6.75% gc time)

julia> @time update_B!(b);
  0.007372 seconds (1 allocation: 32 bytes)
```

The only difference between `A` and `B` is that I have a parametric inner constructor in `A`, and somehow this affects the performance of constructing instances. I initially thought it was an `Accessors` issue (https://github.com/JuliaObjects/Accessors.jl/issues/148) but then @aplavin pointed out it was actually something happening even without it.","reactions":{"url":"https://api.github.com/repos/JuliaLang/julia/issues/54272/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/JuliaLang/julia/issues/54272/timeline","performed_via_github_app":null,"state_reason":null}}

